impacted_block_content:
resource "aws_lb_listener_rule" "setup_mpc_map" {
  listener_arn = "${data.terraform_remote_state.setup_iac.outputs.alb_listener_arn}"
  priority     = 300

  action {
    type             = "forward"
    target_group_arn = "${aws_alb_target_group.setup_mpc_map.arn}"
  }

  condition {
    field  = "path-pattern"
    values = ["*"]
  }
}

file_content:
terraform {
  backend "s3" {
    bucket = "aztec-terraform"
    key    = "setup/setup-mpc-map"
    region = "eu-west-2"
  }
}

data "terraform_remote_state" "setup_iac" {
  backend = "s3"
  config = {
    bucket = "aztec-terraform"
    key    = "setup/setup-iac"
    region = "eu-west-2"
  }
}

provider "aws" {
  profile = "default"
  region  = "eu-west-2"
}

resource "aws_service_discovery_service" "setup_mpc_map" {
  name = "setup-mpc-map"

  health_check_custom_config {
    failure_threshold = 1
  }

  dns_config {
    namespace_id = "${data.terraform_remote_state.setup_iac.outputs.local_service_discovery_id}"

    dns_records {
      ttl  = 10
      type = "A"
    }

    routing_policy = "MULTIVALUE"
  }
}

resource "aws_ecs_task_definition" "setup_mpc_map" {
  family                   = "setup-mpc-map"
  requires_compatibilities = ["FARGATE"]
  network_mode             = "awsvpc"
  cpu                      = "256"
  memory                   = "512"
  execution_role_arn       = "${data.terraform_remote_state.setup_iac.outputs.ecs_task_execution_role_arn}"

  container_definitions = <<DEFINITIONS
[
  {
    "name": "setup-mpc-map",
    "image": "278380418400.dkr.ecr.eu-west-2.amazonaws.com/setup-mpc-map:latest",
    "essential": true,
    "portMappings": [
      {
        "containerPort": 80
      }
    ],
    "environment": [
      {
        "name": "NODE_ENV",
        "value": "production"
      },
      {
        "name": "PORT",
        "value": "80"
      }
    ],
    "logConfiguration": {
      "logDriver": "awslogs",
      "options": {
        "awslogs-group": "/fargate/service/setup-mpc-map",
        "awslogs-region": "eu-west-2",
        "awslogs-stream-prefix": "ecs"
      }
    }
  }
]
DEFINITIONS
}

data "aws_ecs_task_definition" "setup_mpc_map" {
  task_definition = "${aws_ecs_task_definition.setup_mpc_map.family}"
}

resource "aws_ecs_service" "setup_mpc_map" {
  name          = "setup-mpc-map"
  cluster       = "${data.terraform_remote_state.setup_iac.outputs.ecs_cluster_id}"
  launch_type   = "FARGATE"
  desired_count = "1"

  network_configuration {
    subnets = [
      "${data.terraform_remote_state.setup_iac.outputs.subnet_az1_private_id}",
      "${data.terraform_remote_state.setup_iac.outputs.subnet_az2_private_id}"
    ]
    security_groups = ["${data.terraform_remote_state.setup_iac.outputs.security_group_private_id}"]
  }

  load_balancer {
    target_group_arn = "${aws_alb_target_group.setup_mpc_map.arn}"
    container_name   = "setup-mpc-map"
    container_port   = 80
  }

  service_registries {
    registry_arn = "${aws_service_discovery_service.setup_mpc_map.arn}"
  }

  # Track the latest ACTIVE revision
  task_definition = "${aws_ecs_task_definition.setup_mpc_map.family}:${max("${aws_ecs_task_definition.setup_mpc_map.revision}", "${data.aws_ecs_task_definition.setup_mpc_map.revision}")}"

  lifecycle {
    ignore_changes = ["task_definition"]
  }
}

# Logs
resource "aws_cloudwatch_log_group" "setup_mpc_map_logs" {
  name              = "/fargate/service/setup-mpc-map"
  retention_in_days = "14"
}

# Configure ALB route.
resource "aws_alb_target_group" "setup_mpc_map" {
  name        = "setup-mpc-map"
  port        = "80"
  protocol    = "HTTP"
  target_type = "ip"
  vpc_id      = "${data.terraform_remote_state.setup_iac.outputs.vpc_id}"
  tags = {
    name = "setup-mpc-map"
  }
}

resource "aws_lb_listener_rule" "setup_mpc_map" {
  listener_arn = "${data.terraform_remote_state.setup_iac.outputs.alb_listener_arn}"
  priority     = 300

  action {
    type             = "forward"
    target_group_arn = "${aws_alb_target_group.setup_mpc_map.arn}"
  }

  condition {
    field  = "path-pattern"
    values = ["*"]
  }
}

# Copyright (c) 2024 Oracle Corporation and/or affiliates.  All rights reserved.
# Licensed under the Universal Permissive License v 1.0 as shown at https://oss.oracle.com/licenses/upl

resource "oci_load_balancer_load_balancer" "lb" {
  count          = var.create_load_balancer ? 1 : 0
  compartment_id = var.compartment_id
  display_name   = "${var.prefix}-load-balancer"
  shape          = lookup(var.load_balancer_shape, "shape")
  subnet_ids     = [var.subnet_id]
  is_private     = "true"

  # Optional
  shape_details {
    minimum_bandwidth_in_mbps = lookup(var.load_balancer_shape, "flex_min")
    maximum_bandwidth_in_mbps = lookup(var.load_balancer_shape, "flex_max")
  }
  freeform_tags = var.freeform_tags
}

resource "oci_load_balancer_backend_set" "lb_backend" {
  health_checker {
    protocol = var.load_balancer_protocol
    port     = var.load_balancer_port
    url_path = "/sys/health"
  }

  load_balancer_id = local.lb_ocid
  name             = "${var.prefix}-lb-backend"
  policy           = var.load_balancer_policy
}

resource "oci_core_instance_configuration" "instance_config" {
  compartment_id = var.compartment_id
  display_name   = "${var.prefix}-instance-configuration"
  freeform_tags  = var.freeform_tags

  instance_details {
    instance_type = "compute"

    launch_details {
      availability_domain = var.availability_domain_id
      compartment_id      = var.compartment_id
      display_name        = "${var.prefix}-compute"
      shape               = lookup(var.instance_shape, "shape", "VM.Standard2.2")

      dynamic "shape_config" {
        for_each = length(regexall("Flex", lookup(var.instance_shape, "shape", "VM.Standard.E3.Flex"))) > 0 ? [1] : []
        content {
          ocpus         = max(1, lookup(var.instance_shape, "ocpus", 1))
          memory_in_gbs = (lookup(var.instance_shape, "memory", 4) / lookup(var.instance_shape, "ocpus", 1)) > 64 ? (lookup(var.instance_shape, "ocpus", 1) * 16) : lookup(var.instance_shape, "memory", 4)
        }
      }

      source_details {
        source_type             = "image"
        image_id                = var.image_ocid
        boot_volume_size_in_gbs = lookup(var.instance_shape, "boot_volume_size", null)
      }

      metadata = {
        ssh_authorized_keys = file(var.ssh_public_key_path)
        user_data           = var.instance_user_data
      }

      create_vnic_details {
        assign_public_ip = "false"
        subnet_id        = var.subnet_id
      }
    }
  }
}

resource "oci_core_instance_pool" "instance_pool" {
  depends_on                = [oci_load_balancer_backend_set.lb_backend]
  instance_configuration_id = oci_core_instance_configuration.instance_config.id
  compartment_id            = var.compartment_id
  display_name              = "${var.prefix}-instance-pool"
  size                      = var.pool_size
  freeform_tags             = var.freeform_tags

  placement_configurations {
    availability_domain = var.availability_domain_id
    primary_subnet_id   = var.subnet_id
  }

  load_balancers {
    backend_set_name = "${var.prefix}-lb-backend"
    load_balancer_id = local.lb_ocid
    port             = var.load_balancer_port
    vnic_selection   = "PrimaryVnic"
  }
}

resource "oci_load_balancer_listener" "listener" {
  depends_on               = [oci_core_instance_pool.instance_pool, oci_load_balancer_backend_set.lb_backend]
  default_backend_set_name = oci_core_instance_pool.instance_pool.load_balancers[0].backend_set_name
  load_balancer_id         = local.lb_ocid
  name                     = "${var.prefix}-listener"
  port                     = var.load_balancer_port
  protocol                 = var.load_balancer_protocol
}

# Copyright (c) 2024 Oracle Corporation and/or affiliates.  All rights reserved.
# Licensed under the Universal Permissive License v 1.0 as shown at https://oss.oracle.com/licenses/upl

